<?php
namespace App\Http\Controllers;
use App\Models\Category; use App\Models\PendingTransaction; use App\Models\TelegramConnection; use App\Models\TelegramPairingCode; use App\Models\TelegramUpdate; use App\Models\SystemSetting; use App\Models\Transaction; use App\Services\CategoryResolver; use App\Services\GroqTransactionParser; use App\Services\TelegramReportService; use App\Services\TransactionInputNormalizer; use Barryvdh\DomPDF\Facade\Pdf; use Illuminate\Http\Request; use Illuminate\Support\Carbon; use Illuminate\Support\Facades\Http; use Illuminate\Support\Facades\Log; use Illuminate\Support\Facades\Storage;
class TelegramWebhookController extends Controller {
 public function __construct(private GroqTransactionParser $parser,private TransactionInputNormalizer $normalizer,private CategoryResolver $categories,private TelegramReportService $reports){}
 private function token():?string{return SystemSetting::read('telegram_bot_token',config('services.telegram.bot_token'));}
 private function send(string $chatId,string $text,?array $keyboard=null):void{$text=str_replace(['\\n','\\r'],["\n","\r"],$text);if($chatId===''||!$this->token())return;try{$data=['chat_id'=>$chatId,'text'=>$text];if($keyboard)$data['reply_markup']=json_encode(['inline_keyboard'=>$keyboard]);Http::timeout(10)->post('https://api.telegram.org/bot'.$this->token().'/sendMessage',$data);}catch(\Throwable $e){Log::error('Telegram sendMessage gagal',['error'=>$e->getMessage()]);}}
 private function typing(string $chatId):void{if($chatId===''||!$this->token())return;try{Http::timeout(5)->post('https://api.telegram.org/bot'.$this->token().'/sendChatAction',['chat_id'=>$chatId,'action'=>'typing']);}catch(\Throwable $e){Log::warning('Telegram typing indicator gagal',['error'=>$e->getMessage()]);}}
 private function answerCallback(string $id):void{if(!$this->token())return;Http::timeout(10)->post('https://api.telegram.org/bot'.$this->token().'/answerCallbackQuery',['callback_query_id'=>$id]);}
 private function menuKeyboard():array{return ['keyboard'=>[[['text'=>'💰 Saldo'],['text'=>'📊 Laporan']], [['text'=>'🧠 Analisa'],['text'=>'📥 Pemasukan']], [['text'=>'📤 Pengeluaran'],['text'=>'🧾 Transaksi terbaru']], [['text'=>'❓ Bantuan']]],'resize_keyboard'=>true,'is_persistent'=>true];}
 private function sendWithMenu(string $chatId,string $text):void{if($chatId===''||!$this->token())return;try{Http::timeout(10)->post('https://api.telegram.org/bot'.$this->token().'/sendMessage',['chat_id'=>$chatId,'text'=>$text,'reply_markup'=>json_encode($this->menuKeyboard())]);}catch(\Throwable $e){Log::error('Telegram menu gagal',['error'=>$e->getMessage()]);}}
 private function helpText():string{return "Panduan Lengkap Bot Keuangan\n\n1. HUBUNGKAN TELEGRAM\nBuat kode pairing dari website, lalu kirim:\n/hubungkan KODE\n\n2. CATAT TRANSAKSI\nContoh pemasukan:\n• gaji 5jt\n• bonus 500rb\n• freelance 1,5 juta tanggal 10\n• terima transfer 750k\n\nContoh pengeluaran:\n• makan 10k\n• jajan 15 ribu kemarin\n• belanja 125.000\n• bensin 50k tadi pagi\n• jajajan susu pagi tadi 5k\n• listrik 250rb 12/09/2026\n\n3. INPUT NOTA\nKirim foto nota pembayaran. Bot akan membaca total, tanggal, keterangan, dan kategori lalu meminta konfirmasi. Foto nota disimpan sebagai bukti transaksi.\n\n4. NOMINAL\n• 10k, 10rb, 10 ribu = Rp10.000\n• 1,5 juta = Rp1.500.000\n• 500.000 = Rp500.000\n\n5. TANGGAL\n• hari ini, tadi, pagi tadi\n• kemarin\n• tanggal 12\n• tanggal 5 bulan lalu\n• 12/09/2026\nJika hanya menulis tanggal, bulan dan tahun aktif akan digunakan.\n\n6. KONFIRMASI\nBot akan menampilkan detail transaksi terlebih dahulu. Tekan Ya, simpan atau Batal. Jika ada yang keliru, tekan Edit Jenis, Edit Kategori, Edit Tanggal, Edit Nominal, atau Edit Keterangan lalu kirim nilai barunya. Jika kategori tidak dikenali, bot otomatis memakai Pengeluaran - Lainnya dan tetap meminta konfirmasi.\nGunakan /batal untuk membatalkan transaksi yang sedang menunggu konfirmasi.\n\n7. EXPORT PDF\n• export\n• export laporan bulan ini\n• export laporan bulan Juli\n• export laporan bulan Agustus 2026\n• print laporan bulan Mei\nPDF akan dikirim langsung ke chat Telegram.\n\n8. LAPORAN\n• saldo\n• laporan bulan ini\n• total pemasukan bulan ini\n• total pengeluaran bulan ini\n• pemasukan bulan lalu\n• pengeluaran kemarin\n• transaksi terbaru\n• cari transaksi makan\n• bandingkan bulan ini dengan bulan lalu\n\n9. ANALISA KEUANGAN\n• analisa bulan ini\n• insight bulan ini\n• kondisi keuangan saya\nBot akan menghitung saldo, rata-rata pengeluaran, kategori terbesar, dan transaksi terbesar.\n\n10. PERINTAH MENU\n/start - Mulai bot\n/menu - Tampilkan menu tombol\n/saldo - Lihat saldo bulan ini\n/laporan - Lihat ringkasan keuangan\n/export - Export laporan PDF\n/analisa - Lihat analisa keuangan\n/pemasukan - Total pemasukan\n/pengeluaran - Total pengeluaran\n/transaksi - Transaksi terbaru\n/cari kata - Cari transaksi\n/bantuan - Tampilkan panduan ini\n/batal - Batalkan konfirmasi\n/kategori - Lihat kategori aktif\n/tambahkategori pengeluaran Hiburan - Tambah kategori\n/ubahkategori Hiburan menjadi Entertainment - Ubah kategori\n/nonaktifkategori Entertainment - Nonaktifkan kategori\n\nCatatan: pesan seperti transfer 500k akan diklarifikasi sebagai pemasukan atau pengeluaran sebelum diproses.";}
 public function handle(Request $request){$expected=(string)SystemSetting::read('telegram_webhook_secret',config('services.telegram.webhook_secret'));if($expected===''||!hash_equals($expected,(string)$request->header('X-Telegram-Bot-Api-Secret-Token')))return response()->json(['ok'=>false],403);$updateId=$request->integer('update_id');if(!$updateId)return response()->json(['ok'=>true]);if(TelegramUpdate::where('update_id',$updateId)->exists())return response()->json(['ok'=>true,'duplicate'=>true]);$callback=$request->input('callback_query');$message=$request->input('message',[]);$chatId=(string)($callback['message']['chat']['id']??$message['chat']['id']??'');TelegramUpdate::create(['update_id'=>$updateId,'chat_id'=>$chatId,'processed_at'=>now()]);if($callback){$this->handleCallback($chatId,(string)($callback['data']??''),(string)($callback['id']??''));return response()->json(['ok'=>true]);}$text=trim((string)($message['text']??''));$photo=$message['photo']??[];if($text!==''||$photo)$this->typing($chatId);$from=$message['from']??[];if($photo)$this->parsePhotoTransaction($chatId,$photo,(string)($message['caption']??''));elseif(preg_match('/^\/start(?:@\w+)?/i',$text)){$this->sendWithMenu($chatId,"Halo! Saya bot Keuangan.\n\nHubungkan akun dengan mengirim:\n/hubungkan KODE\n\nKODE dibuat dari menu Telegram di website.\n\n".$this->helpText());}elseif(preg_match('/^\/menu(?:@\w+)?/i',$text))$this->sendWithMenu($chatId,'Menu bot siap digunakan.');elseif(preg_match('/^\/bantuan(?:@\w+)?/i',$text)||in_array(mb_strtolower($text),['❓ bantuan','bantuan'],true))$this->sendWithMenu($chatId,$this->helpText());elseif(preg_match('/^\/hubungkan(?:@\w+)?\s+([A-Z0-9]{8})$/i',$text,$match))$this->pair($chatId,strtoupper($match[1]),$from);elseif(preg_match('/^\/(batal|cancel)(?:@\w+)?/i',$text)){$pending=PendingTransaction::where('chat_id',$chatId)->where('status','pending')->latest()->first();if($pending){if($pending->payload['receipt_path']??null)Storage::disk('public')->delete($pending->payload['receipt_path']);$pending->update(['status'=>'cancelled']);}$this->send($chatId,'Transaksi dibatalkan.');}elseif($connection=TelegramConnection::with('wallet')->where('chat_id',$chatId)->where('is_active',true)->first()){if($this->isExportCommand($text))$this->exportTelegramReport($chatId,$text,$connection->wallet);elseif($this->isCategoryCommand($text))$this->handleCategoryCommand($chatId,$text,$connection->wallet,$connection->user_id);else{$report=$this->reports->respond($connection->wallet,$text,now()->timezone('Asia/Jakarta'));if($report!==null)$this->send($chatId,$report);else $this->parseTransaction($chatId,$text);}}else $this->send($chatId,'Akun Telegram ini belum terhubung. Gunakan /start untuk melihat cara pairing.');return response()->json(['ok'=>true]);}
 private function pair(string $chatId,string $code,array $from):void{$pairing=TelegramPairingCode::with('wallet')->where('code',$code)->whereNull('used_at')->where('expires_at','>',now())->first();if(!$pairing){$this->send($chatId,'Kode pairing tidak valid atau sudah kedaluwarsa. Buat kode baru dari website.');return;}$existing=TelegramConnection::where('chat_id',$chatId)->where('is_active',true)->first();if($existing&&$existing->wallet_id!==$pairing->wallet_id){$this->send($chatId,'Telegram ini sudah terhubung ke dompet lain. Putuskan koneksi lama terlebih dahulu.');return;}TelegramConnection::updateOrCreate(['chat_id'=>$chatId],['wallet_id'=>$pairing->wallet_id,'user_id'=>$pairing->user_id,'telegram_username'=>$from['username']??null,'telegram_name'=>trim(($from['first_name']??'').' '.($from['last_name']??'')),'is_active'=>true,'connected_at'=>now()]);$pairing->update(['used_at'=>now()]);$this->send($chatId,"Berhasil terhubung ke {$pairing->wallet->name}. Coba kirim: makan 10k kemarin");}
 private function parseTransaction(string $chatId,string $text):void{$connection=TelegramConnection::where('chat_id',$chatId)->where('is_active',true)->first();$editing=PendingTransaction::where('chat_id',$chatId)->where('status','pending')->latest()->first();if($editing&&($editing->payload['editing']??null)){ $this->applyPendingEdit($editing,$text,$connection->wallet);return;}try{$now=now()->timezone('Asia/Jakarta');$parsed=$this->parser->parse($text,$now->toDateString(),$now->month,$now->year);if(($parsed['intent']??'')!=='create_transaction')throw new \RuntimeException('Saya belum memahami pesan ini sebagai pencatatan transaksi. Contoh: makan 10k kemarin.');if(!in_array($parsed['type']??'unknown',['income','expense'],true))throw new \RuntimeException('Ini termasuk pemasukan atau pengeluaran? Contoh: gaji 5jt atau makan 10k.');if(!empty($parsed['missing_fields']))throw new \RuntimeException('Data belum lengkap: '.implode(', ',$parsed['missing_fields']).'.');$amount=$this->normalizer->amount($parsed['amount']);$date=$this->normalizer->date($parsed['date_expression'],$now,$now->month,$now->year);$category=$this->categories->find($connection->wallet,$parsed['type'],$parsed['category'].' '.$parsed['description']);$usedFallback=false;if(!$category){$parsed['type']='expense';$category=$this->categories->fallback($connection->wallet,'expense',$connection->user_id);$usedFallback=true;}$pending=PendingTransaction::create(['wallet_id'=>$connection->wallet_id,'user_id'=>$connection->user_id,'chat_id'=>$chatId,'payload'=>['category_id'=>$category->id,'type'=>$parsed['type'],'transaction_date'=>$date,'description'=>$parsed['description'],'amount'=>$amount,'category_fallback'=>$usedFallback,'category_name'=>$category->name],'expires_at'=>now()->addMinutes(10)]);$this->renderPending($chatId,$pending);}catch(\Throwable $e){$this->send($chatId,$e->getMessage());}}
 private function handleCallback(string $chatId,string $data,string $callbackId):void{$this->answerCallback($callbackId);if(preg_match('/^category:(confirm|cancel):(\d+)$/',$data,$categoryMatch)){$this->handleCategoryCallback($chatId,$categoryMatch[1],(int)$categoryMatch[2]);return;}if(!preg_match('/^pending:(save|cancel|edit):(\d+)(?::(type|category|date|amount|description))?$/',$data,$match))return;$pending=PendingTransaction::where('id',$match[2])->where('chat_id',$chatId)->where('status','pending')->first();if(!$pending||!$pending->isValid()){$this->send($chatId,'Konfirmasi sudah kedaluwarsa. Silakan kirim ulang transaksi.');return;}if($match[1]==='cancel'){if($pending->payload['receipt_path']??null)Storage::disk('public')->delete($pending->payload['receipt_path']);$pending->update(['status'=>'cancelled']);$this->send($chatId,'Transaksi dibatalkan.');return;}if($match[1]==='edit'){$payload=$pending->payload;$payload['editing']=$match[3];$pending->update(['payload'=>$payload]);$labels=['type'=>'jenis transaksi (Pemasukan/Pengeluaran)','category'=>'kategori','date'=>'tanggal (contoh 22/07/2026 atau kemarin)','amount'=>'nominal (contoh 10k atau 50000)','description'=>'keterangan'];$this->send($chatId,'Kirim '.$labels[$match[3]].'.');return;}Transaction::create(array_merge($pending->payload,['user_id'=>$pending->user_id,'wallet_id'=>$pending->wallet_id]));$pending->update(['status'=>'saved']);$this->send($chatId,'Transaksi berhasil disimpan ke Dompet Keluarga.');}
 private function confirmationKeyboard(int $id):array{return [[['text'=>'Ya, simpan','callback_data'=>'pending:save:'.$id],['text'=>'Batal','callback_data'=>'pending:cancel:'.$id]],[['text'=>'✏️ Jenis','callback_data'=>'pending:edit:'.$id.':type'],['text'=>'✏️ Kategori','callback_data'=>'pending:edit:'.$id.':category']],[['text'=>'✏️ Tanggal','callback_data'=>'pending:edit:'.$id.':date'],['text'=>'✏️ Nominal','callback_data'=>'pending:edit:'.$id.':amount'],['text'=>'✏️ Keterangan','callback_data'=>'pending:edit:'.$id.':description']]];}
 private function renderPending(string $chatId,PendingTransaction $pending):void{$payload=$pending->payload;$label=($payload['type']??'expense')==='income'?'Pemasukan':'Pengeluaran';$note=($payload['category_fallback']??false)?"\nCatatan: kategori tidak dikenali, digunakan kategori default Lainnya.":'';if($payload['receipt_path']??null)$note.="\nBukti foto nota tersimpan.";$this->send($chatId,"Saya memahami:\n\nJenis: {$label}\nKategori: ".($payload['category_name']??'Lainnya')."\nKeterangan: {$payload['description']}\nNominal: Rp ".number_format((int)$payload['amount'],0,',','.')."\nTanggal: ".date('d/m/Y',strtotime($payload['transaction_date'])).$note."\n\nSimpan transaksi ini?",$this->confirmationKeyboard($pending->id));}
 private function applyPendingEdit(PendingTransaction $pending,string $text,\App\Models\Wallet $wallet):void{try{$payload=$pending->payload;$field=$payload['editing']??null;unset($payload['editing']);if($field==='type'){$value=mb_strtolower(trim($text));if(str_contains($value,'pemasukan')||in_array($value,['income','masuk','debit'],true))$payload['type']='income';elseif(str_contains($value,'pengeluaran')||in_array($value,['expense','keluar','kredit'],true))$payload['type']='expense';else throw new \RuntimeException('Jenis tidak dikenali. Kirim Pemasukan atau Pengeluaran.');$category=$this->categories->find($wallet,$payload['type'],$payload['category_name']??'');if(!$category)$category=$this->categories->fallback($wallet,$payload['type'],$pending->user_id);$payload['category_id']=$category->id;$payload['category_name']=$category->name;$payload['category_fallback']=false;}elseif($field==='category'){$category=$this->categories->find($wallet,$payload['type'],$text);if(!$category)throw new \RuntimeException('Kategori tidak ditemukan. Ketik nama kategori yang tersedia, atau gunakan Lainnya.');$payload['category_id']=$category->id;$payload['category_name']=$category->name;$payload['category_fallback']=false;}elseif($field==='date'){$now=now()->timezone('Asia/Jakarta');$payload['transaction_date']=$this->normalizer->date($text,$now,$now->month,$now->year);}elseif($field==='amount')$payload['amount']=$this->normalizer->amount($text);elseif($field==='description'){$description=trim($text);if($description==='')throw new \RuntimeException('Keterangan tidak boleh kosong.');$payload['description']=$description;}else throw new \RuntimeException('Field edit tidak dikenali.');$pending->update(['payload'=>$payload]);$this->renderPending($pending->chat_id,$pending);}catch(\Throwable $e){$payload=$pending->payload;$pending->update(['payload'=>$payload]);$this->send($pending->chat_id,$e->getMessage().'\nSilakan tekan tombol edit lagi untuk mencoba.');}}
 private function isCategoryCommand(string $text):bool{return preg_match('/^(?:\\/kategori(?:@\\w+)?|\\/tambahkategori(?:@\\w+)?|\\/ubahkategori(?:@\\w+)?|\\/nonaktifkategori(?:@\\w+)?|kategori|tambah\\s+kategori|buat\\s+kategori|ubah\\s+kategori|ganti\\s+kategori|nonaktifkan\\s+kategori|hapus\\s+kategori)\\b/iu',trim($text))===1;}
 private function categoryKeyboard(int $id):array{return [[['text'=>'Ya, lanjutkan','callback_data'=>'category:confirm:'.$id],['text'=>'Batal','callback_data'=>'category:cancel:'.$id]]];}
 private function categoryType(string $value):?string{$value=mb_strtolower(trim($value));if(in_array($value,['pemasukan','income','masuk'],true))return 'income';if(in_array($value,['pengeluaran','expense','keluar'],true))return 'expense';return null;}
 private function findCategory(\App\Models\Wallet $wallet,string $name):?Category{$name=mb_strtolower(trim($name));return $wallet->categories()->where('is_active',true)->whereRaw('LOWER(name) = ?',[$name])->first();}
 private function handleCategoryCommand(string $chatId,string $text,\App\Models\Wallet $wallet,int $userId):void{$text=trim($text);if(preg_match('/^(?:\\/kategori(?:@\\w+)?|kategori)$/iu',$text)){ $categories=$wallet->categories()->where('is_active',true)->orderBy('type')->orderBy('name')->get()->groupBy('type');$lines=['Daftar kategori aktif:'];foreach(['income'=>'Pemasukan','expense'=>'Pengeluaran'] as $type=>$label){$lines[]='';$lines[]=$label.':';foreach($categories->get($type,collect()) as $category)$lines[]='• '.$category->name;}$this->send($chatId,implode("\\n",$lines));return;}$payload=null;if(preg_match('/^(?:\\/tambahkategori(?:@\\w+)?\\s+|(?:tambah|buat)\\s+kategori\\s+)(pemasukan|pengeluaran|income|expense|masuk|keluar)\\s+(.+)$/iu',$text,$match)){$type=$this->categoryType($match[1]);$name=trim($match[2]);if(mb_strlen($name)>80){$this->send($chatId,'Nama kategori maksimal 80 karakter.');return;}if($wallet->categories()->where('type',$type)->whereRaw('LOWER(name) = ?', [mb_strtolower($name)])->exists()){$this->send($chatId,'Kategori tersebut sudah tersedia.');return;}$payload=['kind'=>'category_action','action'=>'create','type'=>$type,'name'=>$name];$prompt='Tambahkan kategori '.$type.' dengan nama "'.$name.'"?';}elseif(preg_match('/^(?:\\/ubahkategori(?:@\\w+)?\\s+|(?:ubah|ganti)\\s+kategori\\s+)(.+?)\\s+(?:menjadi|ke)\\s+(.+)$/iu',$text,$match)){$category=$this->findCategory($wallet,$match[1]);$name=trim($match[2]);if(!$category){$this->send($chatId,'Kategori aktif tidak ditemukan. Gunakan /kategori untuk melihat daftar.');return;}if(mb_strlen($name)>80||$name===''){$this->send($chatId,'Nama kategori tidak valid.');return;}if($wallet->categories()->where('id','!=',$category->id)->whereRaw('LOWER(name) = ?', [mb_strtolower($name)])->exists()){$this->send($chatId,'Nama kategori tersebut sudah digunakan.');return;}$payload=['kind'=>'category_action','action'=>'rename','category_id'=>$category->id,'old_name'=>$category->name,'name'=>$name];$prompt='Ubah kategori "'.$category->name.'" menjadi "'.$name.'"?';}elseif(preg_match('/^(?:\\/nonaktifkategori(?:@\\w+)?\\s+|(?:nonaktifkan|hapus)\\s+kategori\\s+)(.+)$/iu',$text,$match)){$category=$this->findCategory($wallet,$match[1]);if(!$category){$this->send($chatId,'Kategori aktif tidak ditemukan. Gunakan /kategori untuk melihat daftar.');return;}$payload=['kind'=>'category_action','action'=>'deactivate','category_id'=>$category->id,'name'=>$category->name]; $prompt='Nonaktifkan kategori "'.$category->name.'"? Data transaksi lama tetap aman.';}else{$this->send($chatId,"Format kategori belum dikenali.\\n\\nContoh:\\n/kategori\\n/tambahkategori pengeluaran Hiburan\\n/ubahkategori Hiburan Entertainment\\n/nonaktifkategori Entertainment");return;}$pending=PendingTransaction::create(['wallet_id'=>$wallet->id,'user_id'=>$userId,'chat_id'=>$chatId,'payload'=>$payload,'expires_at'=>now()->addMinutes(10)]);$this->send($chatId,$prompt,$this->categoryKeyboard($pending->id));}
 private function handleCategoryCallback(string $chatId,string $action,int $id):void{$pending=PendingTransaction::where('id',$id)->where('chat_id',$chatId)->where('status','pending')->first();if(!$pending||!$pending->isValid()||($pending->payload['kind']??null)!=='category_action'){$this->send($chatId,'Konfirmasi kategori sudah kedaluwarsa.');return;}if($action==='cancel'){$pending->update(['status'=>'cancelled']);$this->send($chatId,'Perubahan kategori dibatalkan.');return;}$payload=$pending->payload;$wallet=$pending->wallet;if($payload['action']==='create'){$category=Category::create(['wallet_id'=>$wallet->id,'user_id'=>$pending->user_id,'name'=>$payload['name'],'type'=>$payload['type'],'color'=>$payload['type']==='income'?'#10b981':'#ef4444','is_active'=>true]);$message='Kategori '.$category->name.' berhasil ditambahkan.';}elseif($payload['action']==='rename'){$category=$wallet->categories()->where('id',$payload['category_id'])->where('is_active',true)->first();if(!$category){$this->send($chatId,'Kategori sudah tidak tersedia.');return;}$category->update(['name'=>$payload['name']]);$message='Kategori berhasil diubah menjadi '.$payload['name'].'.';}else{$category=$wallet->categories()->where('id',$payload['category_id'])->where('is_active',true)->first();if(!$category){$this->send($chatId,'Kategori sudah tidak tersedia.');return;}if($category->transactions()->exists()){$category->update(['is_active'=>false]);$message='Kategori '.$category->name.' dinonaktifkan. Data lama tetap aman.';}else{$name=$category->name;$category->delete();$message='Kategori '.$name.' berhasil dihapus.';}}$pending->update(['status'=>'saved']);$this->send($chatId,$message);}
 private function isExportCommand(string $text):bool{return preg_match('/^\\/?(?:export|print)\\b/iu',trim($text))===1;}
 private function telegramExportPeriod(string $text):Carbon{$now=now()->timezone('Asia/Jakarta');$months=['januari'=>1,'februari'=>2,'maret'=>3,'april'=>4,'mei'=>5,'juni'=>6,'juli'=>7,'agustus'=>8,'september'=>9,'oktober'=>10,'november'=>11,'desember'=>12];$value=mb_strtolower($text);$month=$now->month;$year=$now->year;if(preg_match('/\\b(januari|februari|maret|april|mei|juni|juli|agustus|september|oktober|november|desember)\\b(?:\\s+(\\d{4}))?/iu',$value,$match)){$month=$months[mb_strtolower($match[1])];if(!empty($match[2]))$year=(int)$match[2];}elseif(preg_match('/\\b(\\d{4})\\b/',$value,$match))$year=(int)$match[1];return Carbon::create($year,$month,1);}
 private function exportTelegramReport(string $chatId,string $text,\App\Models\Wallet $wallet):void{try{$period=$this->telegramExportPeriod($text);$transactions=Transaction::with('category')->where('wallet_id',$wallet->id)->whereYear('transaction_date',$period->year)->whereMonth('transaction_date',$period->month)->oldest('transaction_date')->oldest('id')->get();$previous=$period->copy()->subMonth();$previousIncome=Transaction::where('wallet_id',$wallet->id)->whereYear('transaction_date',$previous->year)->whereMonth('transaction_date',$previous->month)->where('type','income')->sum('amount');$previousExpense=Transaction::where('wallet_id',$wallet->id)->whereYear('transaction_date',$previous->year)->whereMonth('transaction_date',$previous->month)->where('type','expense')->sum('amount');$carryForward=max(0,(float)$previousIncome-(float)$previousExpense);$income=(float)$transactions->where('type','income')->sum('amount');$expense=(float)$transactions->where('type','expense')->sum('amount');$data=compact('period','transactions','carryForward','expense')+['ledgerIncome'=>$income+$carryForward];$filename='buku-kas-'.$period->format('Y-m').'.pdf';$pdf=Pdf::loadView('exports.ledger-pdf',$data)->setPaper('a4','portrait');$response=Http::timeout(30)->attach('document',$pdf->output(),$filename)->post('https://api.telegram.org/bot'.$this->token().'/sendDocument',['chat_id'=>$chatId,'caption'=>'Laporan Buku Kas '.$period->translatedFormat('F Y')]);if(!$response->successful()||!$response->json('ok')){$this->send($chatId,'PDF gagal dikirim. Silakan coba lagi.');Log::error('Telegram sendDocument gagal',['description'=>$response->json('description')]);}}catch(\Throwable $e){Log::error('Export PDF Telegram gagal',['error'=>$e->getMessage()]);$this->send($chatId,'Export PDF gagal: '.$e->getMessage());}}
 private function parsePhotoTransaction(string $chatId,array $photos,string $caption=''):void{ $connection=TelegramConnection::where('chat_id',$chatId)->where('is_active',true)->first();if(!$connection){$this->send($chatId,'Akun Telegram ini belum terhubung. Gunakan /start untuk melihat cara pairing.');return;}$receiptPath=null;try{$photo=end($photos);$fileId=(string)($photo['file_id']??'');if($fileId==='')throw new \RuntimeException('Foto nota tidak valid.');$fileInfo=Http::timeout(15)->get('https://api.telegram.org/bot'.$this->token().'/getFile',['file_id'=>$fileId]);$telegramPath=$fileInfo->json('result.file_path');if(!$fileInfo->successful()||!$telegramPath)throw new \RuntimeException('Foto nota tidak dapat diunduh dari Telegram.');$image=Http::timeout(30)->get('https://api.telegram.org/file/bot'.$this->token().'/'.$telegramPath);if(!$image->successful())throw new \RuntimeException('Foto nota gagal diunduh.');$extension=strtolower(pathinfo($telegramPath,PATHINFO_EXTENSION));$extension=in_array($extension,['jpg','jpeg','png','webp'],true)?$extension:'jpg';$mime=$extension==='jpg'||$extension==='jpeg'?'image/jpeg':'image/'.$extension;$receiptPath='receipts/telegram/'.\Illuminate\Support\Str::uuid().'.'.$extension;if(!Storage::disk('public')->put($receiptPath,$image->body()))throw new \RuntimeException('Foto nota gagal disimpan.');$now=now()->timezone('Asia/Jakarta');$parsed=$this->parser->parseImage('data:'.$mime.';base64,'.base64_encode($image->body()),$now->toDateString(),$now->month,$now->year);if(!empty($parsed['missing_fields']))throw new \RuntimeException('Nota terbaca, tetapi data belum lengkap: '.implode(', ',$parsed['missing_fields']).'. Silakan kirim foto yang lebih jelas.');$amount=$this->normalizer->amount($parsed['amount']);$date=$this->normalizer->date($parsed['date_expression'],$now,$now->month,$now->year);$category=$this->categories->find($connection->wallet,'expense',(string)$parsed['category'].' '.(string)$parsed['description']);$usedFallback=false;if(!$category){$category=$this->categories->fallback($connection->wallet,'expense',$connection->user_id);$usedFallback=true;}$pending=PendingTransaction::create(['wallet_id'=>$connection->wallet_id,'user_id'=>$connection->user_id,'chat_id'=>$chatId,'payload'=>['category_id'=>$category->id,'category_name'=>$category->name,'type'=>'expense','transaction_date'=>$date,'description'=>$parsed['description'],'amount'=>$amount,'receipt_path'=>$receiptPath,'category_fallback'=>$usedFallback,'from_receipt'=>true],'expires_at'=>now()->addMinutes(10)]);$this->renderPending($chatId,$pending);}catch(\Throwable $e){if($receiptPath)Storage::disk('public')->delete($receiptPath);Log::error('Pembacaan nota Telegram gagal',['error'=>$e->getMessage()]);$this->send($chatId,'Saya belum dapat membaca nota tersebut. Pastikan foto cukup jelas dan total pembayaran terlihat.\n\n'.$e->getMessage());}}
}
